final:
module top_module(number, ascii_out);input [3:0] number;
output reg [7:0] ascii_out;

always @ (number) begin
	case(number)
		4'b0000: ascii_out = 8'h30;
		4'b0001: ascii_out = 8'h31;
		4'b0010: ascii_out = 8'h32;
		4'b0011: ascii_out = 8'h33;
		4'b0100: ascii_out = 8'h34;
		4'b0101: ascii_out = 8'h35;
		4'b0110: ascii_out = 8'h36;
		4'b0111: ascii_out = 8'h37;
		4'b1000: ascii_out = 8'h38;
		4'b1001: ascii_out = 8'h39;
		default: ascii_out = 8'h20;
	endcase
end

endmodule
